import React, { useState } from "react";
import WeatherOverlay from "./WeatherOverlay";

export default function WeatherApp() {
  const weatherCondition = "rain";
  const isDaytime = true;

  const cards = [
    { label: "Temperature", value: "36.2°C" },
    { label: "Humidity", value: "70%" },
    { label: "Wind Speed", value: "12 km/h" },
    { label: "UV Index", value: "5 (Moderate)" },
    { label: "Visibility", value: "10 km" },
    { label: "Pressure", value: "1012 hPa" },
  ];

  const [currentIndex, setCurrentIndex] = useState(0);
  const [favorites, setFavorites] = useState(["Atlanta"]);
  const [search, setSearch] = useState("");

  const handleCardClick = () => {
    setCurrentIndex((prev) => (prev + 1) % cards.length);
  };

  const handleAddFavorite = () => {
    if (search && !favorites.includes(search)) {
      setFavorites([...favorites, search]);
      setSearch("");
    }
  };

  const isMobile = window.innerWidth <= 768;

  return (
    <div className="relative flex flex-col items-center justify-start min-h-screen overflow-hidden bg-white dark:bg-black pt-10">
      <WeatherOverlay weatherCondition={weatherCondition} isDaytime={isDaytime} />

      {/* Search + Favorites */}
      <div className="z-10 w-full max-w-md px-4 mb-4">
        <input
          type="text"
          placeholder="Search for a city"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="w-full px-4 py-2 rounded-xl border border-white/20 bg-white/20 text-white backdrop-blur placeholder-white/60"
        />
        <button
          onClick={handleAddFavorite}
          className="mt-2 w-full py-2 bg-purple-500 text-white rounded-xl hover:bg-purple-600"
        >
          Add to Favorites
        </button>
      </div>

      <div className="flex flex-wrap justify-center gap-2 mb-4 z-10">
        {favorites.map((city, idx) => (
          <button
            key={idx}
            className="px-3 py-1 bg-purple-200/40 rounded-full text-white hover:bg-purple-400 transition"
          >
            {city}
          </button>
        ))}
      </div>

      {/* Header */}
      <div className="text-center z-10">
        <h1 className="text-4xl font-bold text-white drop-shadow-glow">
           <span className="text-purple-400">Atlanta</span>
        </h1>
        <p className="text-lg text-white/70 mt-1 capitalize drop-shadow-glow">
          {weatherCondition}
        </p>
      </div>

      {/* Weather Cards */}
      <div className={`mt-6 z-10 w-full px-6 ${isMobile ? "" : "flex justify-center"}`}>
        {isMobile ? (
          <div className="relative w-[200px] h-[140px] cursor-pointer mx-auto" onClick={handleCardClick}>
            {cards.map((card, index) => (
              <div
                key={index}
                className={`absolute top-0 left-0 w-full h-full transition-all duration-500 ease-in-out ${
                  index === currentIndex
                    ? "z-20 opacity-100 scale-100"
                    : "z-0 opacity-0 scale-95"
                } flex flex-col items-center justify-center bg-white/10 backdrop-blur-xl rounded-2xl shadow-xl ring-1 ring-white/20 border-t border-white/30`}
              >
                <p className="text-sm font-semibold text-black-300 drop-shadow-purple mb-1">
                  {card.label}
                </p>
                <p className="text-2xl font-bold text-black-400 drop-shadow-purple">
                  {card.value}
                </p>

                <div className="absolute bottom-1 left-1/2 transform -translate-x-1/2 flex space-x-1 mt-2">
                  {cards.map((_, idx) => (
                    <span
                      key={idx}
                      className={`w-2 h-2 rounded-full ${
                        idx === currentIndex
                          ? "bg-purple-400 scale-110"
                          : "bg-purple-300 opacity-30"
                      } transition-all duration-300`}
                    />
                  ))}
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="grid grid-cols-3 gap-4">
            {cards.map((card, idx) => (
              <div
                key={idx}
                className="w-[180px] h-[120px] flex flex-col items-center justify-center bg-white/10 backdrop-blur-xl rounded-2xl shadow-xl ring-1 ring-white/20 border-t border-white/30"
              >
                <p className="text-sm font-semibold text-black-300 drop-shadow-purple mb-1">
                  {card.label}
                </p>
                <p className="text-xl font-bold text-black-400 drop-shadow-purple">
                  {card.value}
                </p>
              </div>
            ))}
          </div>
        )}
      </div>

      {!isMobile && (
        <div className="text-sm text-white/60 mt-4 z-10"></div>
      )}

      {/* Bottom Navigation */}
      <div className="h-20 fixed bottom-0 left-0 w-full bg-white/30 backdrop-blur-md border-t border-white/40 shadow-lg z-10 flex items-center justify-around rounded-t-2xl">
        {[
          { icon: "🌤", label: "Forecast" },
          { icon: "📡", label: "Radar" },
          { icon: "💬", label: "Community" },
          { icon: "🤖", label: "Weathy" },
        ].map((tab, idx) => (
          <button
            key={idx}
            className="flex flex-col items-center text-gray-800 hover:text-purple-500 transition duration-300"
          >
            <span className="text-xl">{tab.icon}</span>
            <span className="text-xs">{tab.label}</span>
          </button>
        ))}
      </div>
    </div>
  );
}
